onClick:
{{ 
  SelectEst.selectedOptionValue === 'Mantenimiento' 
    ? insertMantenimiento.run()
        .then(() => updateEstadoMaquina.run())
        .then(() => {
            getMantenimientos.run();
            getMaquinas.run();
            getMaquinasActivas.run();
            getMaquinasInactivas.run();
            getMaquinasMantenimiento.run();
            closeModal('ModalEditar');
            showAlert('Mantenimiento registrado', 'success');
        })
    : updateEstadoMaquina.run()
        .then(() => {
  getMaquinas.run();
             getMaquinasActivas.run();
            getMaquinasInactivas.run();
            getMaquinasMantenimiento.run();

            closeModal('ModalEditar');
            showAlert('Estado actualizado', 'success');
        })
}}
